157: /// Computes ttls and updates ttl infos
158: void updateTTL(
159:     const ContextPtr context,
160:     const TTLDescription & ttl_entry,
161:     IMergeTreeDataPart::TTLInfos & ttl_infos,
162:     DB::MergeTreeDataPartTTLInfo & ttl_info,
163:     const Block & block,
164:     bool update_part_min_max_ttls)
165: {
166:     auto expr_and_set = ttl_entry.buildExpression(context);
167:     for (auto & subquery : expr_and_set.sets->getSubqueries())
168:         subquery->buildSetInplace(context);
169: 
170:     auto ttl_column = ITTLAlgorithm::executeExpressionAndGetColumn(expr_and_set.expression, block, ttl_entry.result_column);
171: 
172:     if (const ColumnUInt16 * column_date = typeid_cast<const ColumnUInt16 *>(ttl_column.get()))
173:     {
174:         const auto & date_lut = DateLUT::serverTimezoneInstance();
175:         for (const auto & val : column_date->getData())
176:             ttl_info.update(date_lut.fromDayNum(DayNum(val)));
177:     }
178:     else if (const ColumnUInt32 * column_date_time = typeid_cast<const ColumnUInt32 *>(ttl_column.get()))
179:     {
180:         for (const auto & val : column_date_time->getData())
181:             ttl_info.update(val);
182:     }
183:     else if (const ColumnConst * column_const = typeid_cast<const ColumnConst *>(ttl_column.get()))
184:     {
185:         if (typeid_cast<const ColumnUInt16 *>(&column_const->getDataColumn()))
186:         {
187:             const auto & date_lut = DateLUT::serverTimezoneInstance();
188:             ttl_info.update(date_lut.fromDayNum(DayNum(column_const->getValue<UInt16>())));
189:         }
190:         else if (typeid_cast<const ColumnUInt32 *>(&column_const->getDataColumn()))
191:         {
192:             ttl_info.update(column_const->getValue<UInt32>());
193:         }
194:         else
195:             throw Exception(ErrorCodes::LOGICAL_ERROR, "Unexpected type of result TTL column");
196:     }
197:     else
198:         throw Exception(ErrorCodes::LOGICAL_ERROR, "Unexpected type of result TTL column");
199: 
200:     if (update_part_min_max_ttls)
201:         ttl_infos.updatePartMinMaxTTL(ttl_info.min, ttl_info.max);
202: }
