263: std::vector<AsyncInsertInfoPtr> scatterAsyncInsertInfoBySelector(AsyncInsertInfoPtr async_insert_info, const IColumn::Selector & selector, size_t partition_num)
264: {
265:     if (nullptr == async_insert_info)
266:     {
267:         return {};
268:     }
269:     if (selector.empty())
270:     {
271:         return {async_insert_info};
272:     }
273:     std::vector<AsyncInsertInfoPtr> result(partition_num);
274:     std::vector<Int64> last_row_for_partition(partition_num, -1);
275:     size_t offset_idx = 0;
276:     for (size_t i = 0; i < selector.size(); ++i)
277:     {
278:         ++last_row_for_partition[selector[i]];
279:         if (i + 1 == async_insert_info->offsets[offset_idx])
280:         {
281:             for (size_t part_id = 0; part_id < last_row_for_partition.size(); ++part_id)
282:             {
283:                 Int64 last_row = last_row_for_partition[part_id];
284:                 if (-1 == last_row)
285:                     continue;
286:                 size_t offset = static_cast<size_t>(last_row + 1);
287:                 if (result[part_id] == nullptr)
288:                     result[part_id] = std::make_shared<AsyncInsertInfo>();
289:                 if (result[part_id]->offsets.empty() || offset > *result[part_id]->offsets.rbegin())
290:                 {
291:                     result[part_id]->offsets.push_back(offset);
292:                     result[part_id]->tokens.push_back(async_insert_info->tokens[offset_idx]);
293:                 }
294:             }
295:             ++offset_idx;
296:         }
297:     }
298:     if (offset_idx != async_insert_info->offsets.size())
299:     {
300:         LOG_ERROR(
301:             getLogger("MergeTreeDataWriter"),
302:             "ChunkInfo of async insert offsets doesn't match the selector size {}. Offsets content is ({})",
303:             selector.size(), fmt::join(async_insert_info->offsets.begin(), async_insert_info->offsets.end(), ","));
304:         throw Exception(ErrorCodes::LOGICAL_ERROR, "Unexpected error for async deduplicated insert, please check error logs");
305:     }
306:     return result;
307: }
