489: MergeTreeDataWriter::TemporaryPart MergeTreeDataWriter::writeTempPartImpl(
490:     BlockWithPartition & block_with_partition,
491:     const StorageMetadataPtr & metadata_snapshot,
492:     ContextPtr context,
493:     int64_t block_number,
494:     bool need_tmp_prefix)
495: {
496:     TemporaryPart temp_part;
497:     Block & block = block_with_partition.block;
498: 
499:     auto columns = metadata_snapshot->getColumns().getAllPhysical().filter(block.getNames());
500: 
501:     for (auto & column : columns)
502:         if (column.type->hasDynamicSubcolumnsDeprecated())
503:             column.type = block.getByName(column.name).type;
504: 
505:     auto minmax_idx = std::make_shared<IMergeTreeDataPart::MinMaxIndex>();
506:     minmax_idx->update(block, MergeTreeData::getMinMaxColumnsNames(metadata_snapshot->getPartitionKey()));
507: 
508:     MergeTreePartition partition(block_with_partition.partition);
509: 
510:     MergeTreePartInfo new_part_info(partition.getID(metadata_snapshot->getPartitionKey().sample_block), block_number, block_number, 0);
511:     String part_name;
512:     if (data.format_version < MERGE_TREE_DATA_MIN_FORMAT_VERSION_WITH_CUSTOM_PARTITIONING)
513:     {
514:         DayNum min_date(minmax_idx->hyperrectangle[data.minmax_idx_date_column_pos].left.safeGet<UInt64>());
515:         DayNum max_date(minmax_idx->hyperrectangle[data.minmax_idx_date_column_pos].right.safeGet<UInt64>());
516: 
517:         const auto & date_lut = DateLUT::serverTimezoneInstance();
518: 
519:         auto min_month = date_lut.toNumYYYYMM(min_date);
520:         auto max_month = date_lut.toNumYYYYMM(max_date);
521: 
522:         if (min_month != max_month)
523:             throw Exception(ErrorCodes::LOGICAL_ERROR, "Part spans more than one month.");
524: 
525:         part_name = new_part_info.getPartNameV0(min_date, max_date);
526:     }
527:     else
528:         part_name = new_part_info.getPartNameV1();
529: 
530:     std::string part_dir;
531:     if (need_tmp_prefix)
532:     {
533:         std::string temp_prefix = "tmp_insert_";
534:         const auto & temp_postfix = data.getPostfixForTempInsertName();
535:         if (!temp_postfix.empty())
536:             temp_prefix += temp_postfix + "_";
537:         part_dir = temp_prefix + part_name;
538:     }
539:     else
540:     {
541:         part_dir = part_name;
542:     }
543: 
544:     temp_part.temporary_directory_lock = data.getTemporaryPartDirectoryHolder(part_dir);
545: 
546:     MergeTreeIndices indices;
547:     if (context->getSettingsRef()[Setting::materialize_skip_indexes_on_insert])
548:         indices = MergeTreeIndexFactory::instance().getMany(metadata_snapshot->getSecondaryIndices());
549: 
550:     ColumnsStatistics statistics;
551:     if (context->getSettingsRef()[Setting::materialize_statistics_on_insert])
552:         statistics = MergeTreeStatisticsFactory::instance().getMany(metadata_snapshot->getColumns());
553: 
554:     /// If we need to calculate some columns to sort.
555:     if (metadata_snapshot->hasSortingKey() || metadata_snapshot->hasSecondaryIndices())
556:     {
557:         auto expr = data.getSortingKeyAndSkipIndicesExpression(metadata_snapshot, indices);
558:         addSubcolumnsFromSortingKeyAndSkipIndicesExpression(expr, block);
559:         data.getSortingKeyAndSkipIndicesExpression(metadata_snapshot, indices)->execute(block);
560:     }
561: 
562:     Names sort_columns = metadata_snapshot->getSortingKeyColumns();
563:     std::vector<bool> reverse_flags = metadata_snapshot->getSortingKeyReverseFlags();
564:     SortDescription sort_description;
565:     size_t sort_columns_size = sort_columns.size();
566:     sort_description.reserve(sort_columns_size);
567: 
568:     for (size_t i = 0; i < sort_columns_size; ++i)
569:     {
570:         if (!reverse_flags.empty() && reverse_flags[i])
571:             sort_description.emplace_back(sort_columns[i], -1, 1);
572:         else
573:             sort_description.emplace_back(sort_columns[i], 1, 1);
574:     }
575: 
576:     ProfileEvents::increment(ProfileEvents::MergeTreeDataWriterBlocks);
577: 
578:     /// Sort
579:     IColumn::Permutation * perm_ptr = nullptr;
580:     IColumn::Permutation perm;
581:     if (!sort_description.empty())
582:     {
583:         ProfileEventTimeIncrement<Microseconds> watch(ProfileEvents::MergeTreeDataWriterSortingBlocksMicroseconds);
584: 
585:         if (!isAlreadySorted(block, sort_description))
586:         {
587:             stableGetPermutation(block, sort_description, perm);
588:             perm_ptr = &perm;
589:         }
590:         else
591:             ProfileEvents::increment(ProfileEvents::MergeTreeDataWriterBlocksAlreadySorted);
592:     }
593: 
594:     if ((*data.getSettings())[MergeTreeSetting::optimize_row_order]
595:             && data.merging_params.mode == MergeTreeData::MergingParams::Mode::Ordinary) /// Nobody knows if this optimization messes up specialized MergeTree engines.
596:     {
597:         RowOrderOptimizer::optimize(block, sort_description, perm);
598:         perm_ptr = &perm;
599:     }
