48: /**
49:  * Overview of the merge algorithm
50:  *
51:  * Each merge is executed sequentially block by block.
52:  * The main idea is to make a merge not a subroutine which is executed
53:  * in a thread pool and may occupy a thread for a period of time,
54:  * but to make a merge a coroutine which can suspend the execution
55:  * in some points and then resume the execution from this point.
56:  *
57:  * A perfect point where to suspend the execution is after the work over a block is finished.
58:  * The task itself will be executed via BackgroundJobExecutor.
59:  *
60:  * The interface of the task is simple.
61:  * The main method is `execute()` which will return true, if the task wants to be executed again and false otherwise.
62:  *
63:  * With this kind of task we can give a merge a priority.
64:  * A priority is simple - the lower the size of the merge, the higher priority.
65:  * So, if ClickHouse wants to merge some really big parts into a bigger part,
66:  * then it will be executed for a long time, because the result of the merge is not really needed immediately.
67:  * It is better to merge small parts as soon as possible.
68: */
69: class MergeTask
70: {
71: public:
72: 
73:     MergeTask(
74:         FutureMergedMutatedPartPtr future_part_,
75:         StorageMetadataPtr metadata_snapshot_,
76:         MergeList::Entry * merge_entry_,
77:         std::unique_ptr<MergeListElement> projection_merge_list_element_,
78:         time_t time_of_merge_,
79:         ContextPtr context_,
80:         TableLockHolder & holder,
81:         ReservationSharedPtr space_reservation_,
82:         bool deduplicate_,
83:         Names deduplicate_by_columns_,
84:         bool cleanup_,
85:         MergeTreeData::MergingParams merging_params_,
86:         bool need_prefix,
87:         IMergeTreeDataPart * parent_part_,
88:         String suffix_,
89:         MergeTreeTransactionPtr txn,
90:         MergeTreeData * data_,
91:         MergeTreeDataMergerMutator * mutator_,
92:         PartitionActionBlocker * merges_blocker_,
93:         ActionBlocker * ttl_merges_blocker_)
94:         {
95:             global_ctx = std::make_shared<GlobalRuntimeContext>();
96: 
97:             global_ctx->future_part = std::move(future_part_);
98:             global_ctx->metadata_snapshot = std::move(metadata_snapshot_);
99:             global_ctx->merge_entry = std::move(merge_entry_);
100:             global_ctx->projection_merge_list_element = std::move(projection_merge_list_element_);
101:             global_ctx->merge_list_element_ptr
102:                 = global_ctx->projection_merge_list_element ? global_ctx->projection_merge_list_element.get() : (*global_ctx->merge_entry)->ptr();
103:             global_ctx->time_of_merge = std::move(time_of_merge_);
104:             global_ctx->context = std::move(context_);
