86: void MergeTreeSink::consume(Chunk & chunk)
87: {
88:     if (num_blocks_processed > 0)
89:         storage.delayInsertOrThrowIfNeeded(nullptr, context, false);
90: 
91:     auto block = getHeader().cloneWithColumns(chunk.getColumns());
92:     if (!storage_snapshot->object_columns.empty())
93:         convertDynamicColumnsToTuples(block, storage_snapshot);
94: 
95:     auto part_blocks = MergeTreeDataWriter::splitBlockIntoParts(std::move(block), max_parts_per_block, metadata_snapshot, context);
96: 
97:     using DelayedPartitions = std::vector<MergeTreeSink::DelayedChunk::Partition>;
98:     DelayedPartitions partitions;
99: 
100:     const Settings & settings = context->getSettingsRef();
101:     size_t total_streams = 0;
102:     bool support_parallel_write = false;
103: 
104:     auto token_info = chunk.getChunkInfos().get<DeduplicationToken::TokenInfo>();
105:     if (!token_info)
106:         throw Exception(ErrorCodes::LOGICAL_ERROR,
107:             "TokenInfo is expected for consumed chunk in MergeTreeSink for table: {}",
108:             storage.getStorageID().getNameForLogs());
109: 
110:     const bool need_to_define_dedup_token = !token_info->isDefined();
111: 
112:     String block_dedup_token;
113:     if (token_info->isDefined())
114:         block_dedup_token = token_info->getToken();
115: 
116:     for (auto & current_block : part_blocks)
117:     {
118:         ProfileEvents::Counters part_counters;
119: 
120:         UInt64 elapsed_ns = 0;
121:         MergeTreeDataWriter::TemporaryPart temp_part;
122: 
123:         {
124:             ProfileEventsScope scoped_attach(&part_counters);
125: 
126:             Stopwatch watch;
127:             temp_part = storage.writer.writeTempPart(current_block, metadata_snapshot, context);
128:             elapsed_ns = watch.elapsed();
129:         }
130: 
131:         /// Reset earlier to free memory
132:         current_block.block.clear();
133:         current_block.partition.clear();
134: 
135:         /// If optimize_on_insert setting is true, current_block could become empty after merge
136:         /// and we didn't create part.
137:         if (!temp_part.part)
138:             continue;
139: 
140:         if (need_to_define_dedup_token)
141:         {
142:             chassert(temp_part.part);
143:             const auto hash_value = temp_part.part->getPartBlockIDHash();
144:             token_info->addChunkHash(toString(hash_value.items[0]) + "_" + toString(hash_value.items[1]));
145:         }
146: 
147:         if (!support_parallel_write && temp_part.part->getDataPartStorage().supportParallelWrite())
148:             support_parallel_write = true;
149: 
150:         size_t max_insert_delayed_streams_for_parallel_write;
