152:         if (settings[Setting::max_insert_delayed_streams_for_parallel_write].changed)
153:             max_insert_delayed_streams_for_parallel_write = settings[Setting::max_insert_delayed_streams_for_parallel_write];
154:         else if (support_parallel_write)
155:             max_insert_delayed_streams_for_parallel_write = DEFAULT_DELAYED_STREAMS_FOR_PARALLEL_WRITE;
156:         else
157:             max_insert_delayed_streams_for_parallel_write = 0;
158: 
