160:         size_t current_streams = 0;
161:         for (const auto & stream : temp_part.streams)
162:             current_streams += stream.stream->getNumberOfOpenStreams();
163: 
164:         if (total_streams + current_streams > max_insert_delayed_streams_for_parallel_write)
165:         {
166:             finishDelayedChunk();
167:             delayed_chunk = std::make_unique<MergeTreeSink::DelayedChunk>();
168:             delayed_chunk->partitions = std::move(partitions);
169:             finishDelayedChunk();
170: 
171:             total_streams = 0;
172:             support_parallel_write = false;
173:             partitions = DelayedPartitions{};
174:         }
175: 
176:         partitions.emplace_back(MergeTreeSink::DelayedChunk::Partition
177:         {
178:             .temp_part = std::move(temp_part),
179:             .elapsed_ns = elapsed_ns,
180:             .block_dedup_token = block_dedup_token,
181:             .part_counters = std::move(part_counters),
182:         });
183: 
184:         total_streams += current_streams;
185:     }
186: 
187:     if (need_to_define_dedup_token)
188:     {
189:         token_info->finishChunkHashes();
190:     }
191: 
