199: void MergeTreeSink::finishDelayedChunk()
200: {
201:     if (!delayed_chunk)
202:         return;
203: 
204:     const Settings & settings = context->getSettingsRef();
205: 
206:     for (auto & partition : delayed_chunk->partitions)
207:     {
208:         ProfileEventsScope scoped_attach(&partition.part_counters);
209: 
210:         partition.temp_part.finalize();
211: 
212:         auto & part = partition.temp_part.part;
213: 
214:         bool added = false;
215: 
216:         /// It's important to create it outside of lock scope because
217:         /// otherwise it can lock parts in destructor and deadlock is possible.
218:         MergeTreeData::Transaction transaction(storage, context->getCurrentTransaction().get());
219:         {
220:             auto lock = storage.lockParts();
221:             storage.fillNewPartName(part, lock);
222: 
223:             auto * deduplication_log = storage.getDeduplicationLog();
224: 
225:             if (settings[Setting::insert_deduplicate] && deduplication_log)
226:             {
227:                 const String block_id = part->getZeroLevelPartBlockID(partition.block_dedup_token);
228:                 auto res = deduplication_log->addPart(block_id, part->info);
229:                 if (!res.second)
230:                 {
231:                     ProfileEvents::increment(ProfileEvents::DuplicatedInsertedBlocks);
232:                     LOG_INFO(storage.log, "Block with ID {} already exists as part {}; ignoring it", block_id, res.first.getPartNameForLogs());
233:                     continue;
234:                 }
235:             }
236: 
237:             /// FIXME: renames for MergeTree should be done under the same lock
238:             /// to avoid removing extra covered parts after merge.
239:             ///
240:             /// Image the following:
241:             /// - T1: all_2_2_0 is in renameParts()
242:             /// - T2: merge assigned for [all_1_1_0, all_3_3_0]
243:             /// - T1: renameParts() finished, part had been added as Active
244:             /// - T2: merge finished, covered parts removed, and it will include all_2_2_0!
245:             ///
246:             /// Hence, for now rename_in_transaction is false.
247:             added = storage.renameTempPartAndAdd(part, transaction, lock, /*rename_in_transaction=*/ false);
248:             transaction.commit(&lock);
249:         }
250: 
251:         /// Part can be deduplicated, so increment counters and add to part log only if it's really added
252:         if (added)
253:         {
254:             partition.temp_part.prewarmCaches();
255: 
256:             auto counters_snapshot = std::make_shared<ProfileEvents::Counters::Snapshot>(partition.part_counters.getPartiallyAtomicSnapshot());
257:             PartLog::addNewPart(storage.getContext(), PartLog::PartLogEntry(part, partition.elapsed_ns, counters_snapshot));
258:             StorageMergeTree::incrementInsertedPartsProfileEvent(part->getType());
259: 
260:             /// Initiate async merge - it will be done if it's good time for merge and if there are space in 'background_pool'.
261:             storage.background_operations_assignee.trigger();
262:         }
263:     }
264: 
265:     delayed_chunk.reset();
266: }
267: 
