{"content":"150: /// Converts sample size to an approximate number of rows (ex. `SAMPLE 1000000`) to relative value (ex. `SAMPLE 0.1`).
151: static RelativeSize convertAbsoluteSampleSizeToRelative(const ASTSampleRatio::Rational & ratio, size_t approx_total_rows)
152: {
153:     if (approx_total_rows == 0)
154:         return 1;
155: 
156:     auto absolute_sample_size = ratio.numerator / ratio.denominator;
157:     return std::min(RelativeSize(1), RelativeSize(absolute_sample_size) / RelativeSize(approx_total_rows));
158: }
