191: MergeTreeDataSelectSamplingData MergeTreeDataSelectExecutor::getSampling(
192:     const SelectQueryInfo & select_query_info,
193:     NamesAndTypesList available_real_columns,
194:     const MergeTreeData::DataPartsVector & parts,
195:     KeyCondition & key_condition,
196:     const MergeTreeData & data,
197:     const StorageMetadataPtr & metadata_snapshot,
198:     ContextPtr context,
199:     LoggerPtr log)
200: {
201:     const Settings & settings = context->getSettingsRef();
202:     /// Sampling.
203:     MergeTreeDataSelectSamplingData sampling;
204: 
205:     RelativeSize relative_sample_size = 0;
206:     RelativeSize relative_sample_offset = 0;
207: 
208:     bool final = false;
209:     std::optional<ASTSampleRatio::Rational> sample_size_ratio;
210:     std::optional<ASTSampleRatio::Rational> sample_offset_ratio;
211: 
212:     if (select_query_info.table_expression_modifiers)
213:     {
214:         const auto & table_expression_modifiers = *select_query_info.table_expression_modifiers;
215:         final = table_expression_modifiers.hasFinal();
216:         sample_size_ratio = table_expression_modifiers.getSampleSizeRatio();
217:         sample_offset_ratio = table_expression_modifiers.getSampleOffsetRatio();
218:     }
219:     else
220:     {
221:         auto & select = select_query_info.query->as<ASTSelectQuery &>();
222: 
223:         final = select.final();
224:         auto select_sample_size = select.sampleSize();
225:         auto select_sample_offset = select.sampleOffset();
226: 
227:         if (select_sample_size)
228:             sample_size_ratio = select_sample_size->as<ASTSampleRatio &>().ratio;
229: 
230:         if (select_sample_offset)
231:             sample_offset_ratio = select_sample_offset->as<ASTSampleRatio &>().ratio;
232:     }
233: 
234:     if (sample_size_ratio)
235:     {
236:         relative_sample_size.assign(sample_size_ratio->numerator, sample_size_ratio->denominator);
237: 
238:         if (relative_sample_size < 0)
239:             throw Exception(ErrorCodes::ARGUMENT_OUT_OF_BOUND, "Negative sample size");
240: 
241:         relative_sample_offset = 0;
242:         if (sample_offset_ratio)
243:             relative_sample_offset.assign(sample_offset_ratio->numerator, sample_offset_ratio->denominator);
244: 
245:         if (relative_sample_offset < 0)
246:             throw Exception(ErrorCodes::ARGUMENT_OUT_OF_BOUND, "Negative sample offset");
247: 
248:         /// Convert absolute value of the sampling (in form `SAMPLE 1000000` - how many rows to
249:         /// read) into the relative `SAMPLE 0.1` (how much data to read).
250:         size_t approx_total_rows = 0;
251:         if (relative_sample_size > 1 || relative_sample_offset > 1)
252:             approx_total_rows = getApproximateTotalRowsToRead(parts, metadata_snapshot, key_condition, settings, log);
253: 
254:         if (relative_sample_size > 1)
255:         {
256:             relative_sample_size = convertAbsoluteSampleSizeToRelative(*sample_size_ratio, approx_total_rows);
257:             LOG_DEBUG(log, "Selected relative sample size: {}", toString(relative_sample_size));
258:         }
259: 
260:         /// SAMPLE 1 is the same as the absence of SAMPLE.
261:         if (relative_sample_size == RelativeSize(1))
262:             relative_sample_size = 0;
263: 
264:         if (relative_sample_offset > 0 && RelativeSize(0) == relative_sample_size)
265:             throw Exception(ErrorCodes::ARGUMENT_OUT_OF_BOUND, "Sampling offset is incorrect because no sampling");
266: 
267:         if (relative_sample_offset > 1)
268:         {
269:             relative_sample_offset = convertAbsoluteSampleSizeToRelative(*sample_offset_ratio, approx_total_rows);
270:             LOG_DEBUG(log, "Selected relative sample offset: {}", toString(relative_sample_offset));
271:         }
272:     }
273: 
274:     /** Which range of sampling key values do I need to read?
275:         * First, in the whole range ("universe") we select the interval
276:         *  of relative `relative_sample_size` size, offset from the beginning by `relative_sample_offset`.
277:         *
278:         * Example: SAMPLE 0.4 OFFSET 0.3
279:         *
280:         * [------********------]
281:         *        ^ - offset
282:         *        <------> - size
283:         *
284:         * If the interval passes through the end of the universe, then cut its right side.
285:         *
286:         * Example: SAMPLE 0.4 OFFSET 0.8
287:         *
288:         * [----------------****]
289:         *                  ^ - offset
290:         *                  <------> - size
291:         *
292:         * Next, if the `parallel_replicas_count`, `parallel_replica_offset` settings are set,
293:         *  then it is necessary to break the received interval into pieces of the number `parallel_replicas_count`,
294:         *  and select a piece with the number `parallel_replica_offset` (from zero).
295:         *
296:         * Example: SAMPLE 0.4 OFFSET 0.3, parallel_replicas_count = 2, parallel_replica_offset = 1
297:         *
298:         * [----------****------]
299:         *        ^ - offset
300:         *        <------> - size
301:         *        <--><--> - pieces for different `parallel_replica_offset`, select the second one.
302:         *
303:         * It is very important that the intervals for different `parallel_replica_offset` cover the entire range without gaps and overlaps.
304:         * It is also important that the entire universe can be covered using SAMPLE 0.1 OFFSET 0, ... OFFSET 0.9 and similar decimals.
305:         */
306: 
307:     const bool can_use_sampling_key_parallel_replicas =
308:         settings[Setting::allow_experimental_parallel_reading_from_replicas] > 0
309:         && settings[Setting::max_parallel_replicas] > 1
310:         && settings[Setting::parallel_replicas_mode] == ParallelReplicasMode::SAMPLING_KEY;
311: 
312:     /// Parallel replicas has been requested but there is no way to sample data.
313:     /// Select all data from first replica and no data from other replicas.
314:     if (can_use_sampling_key_parallel_replicas && settings[Setting::parallel_replicas_count] > 1
315:         && !data.supportsSampling() && settings[Setting::parallel_replica_offset] > 0)
316:     {
317:         LOG_DEBUG(
318:             log,
319:             "Will use no data on this replica because parallel replicas processing has been requested"
320:             " (the setting 'max_parallel_replicas') but the table does not support sampling and this replica is not the first.");
321:         sampling.read_nothing = true;
322:         return sampling;
323:     }
324: 
325:     sampling.use_sampling = relative_sample_size > 0 || (can_use_sampling_key_parallel_replicas && settings[Setting::parallel_replicas_count] > 1 && data.supportsSampling());
326:     bool no_data = false; /// There is nothing left after sampling.
327: 
328:     if (sampling.use_sampling)
329:     {
330:         if (relative_sample_size != RelativeSize(0))
331:             sampling.used_sample_factor = 1.0 / boost::rational_cast<Float64>(relative_sample_size);
332: 
333:         RelativeSize size_of_universum = 0;
334:         const auto & sampling_key = metadata_snapshot->getSamplingKey();
335:         DataTypePtr sampling_column_type = sampling_key.data_types.at(0);
336: 
337:         if (sampling_key.data_types.size() == 1)
338:         {
339:             if (typeid_cast<const DataTypeUInt64 *>(sampling_column_type.get()))
340:                 size_of_universum = RelativeSize(std::numeric_limits<UInt64>::max()) + RelativeSize(1);
341:             else if (typeid_cast<const DataTypeUInt32 *>(sampling_column_type.get()))
342:                 size_of_universum = RelativeSize(std::numeric_limits<UInt32>::max()) + RelativeSize(1);
343:             else if (typeid_cast<const DataTypeUInt16 *>(sampling_column_type.get()))
344:                 size_of_universum = RelativeSize(std::numeric_limits<UInt16>::max()) + RelativeSize(1);
345:             else if (typeid_cast<const DataTypeUInt8 *>(sampling_column_type.get()))
346:                 size_of_universum = RelativeSize(std::numeric_limits<UInt8>::max()) + RelativeSize(1);
347:         }
348: 
349:         if (size_of_universum == RelativeSize(0))
350:             throw Exception(ErrorCodes::ILLEGAL_TYPE_OF_COLUMN_FOR_FILTER,
