19: /// Information about partition and the range of blocks contained in the part.
20: /// Allows determining if parts are disjoint or one part fully contains the other.
21: struct MergeTreePartInfo
22: {
23:     String partition_id;
24:     Int64 min_block = 0;
25:     Int64 max_block = 0;
26:     UInt32 level = 0;
27:     Int64 mutation = 0;   /// If the part has been mutated or contains mutated parts, is equal to mutation version number.
28: 
29:     bool use_legacy_max_level = false;  /// For compatibility. TODO remove it
30: 
31:     MergeTreePartInfo() = default;
32: 
33:     MergeTreePartInfo(String partition_id_, Int64 min_block_, Int64 max_block_, UInt32 level_)
34:         : partition_id(std::move(partition_id_)), min_block(min_block_), max_block(max_block_), level(level_)
35:     {
36:     }
37: 
38:     MergeTreePartInfo(String partition_id_, Int64 min_block_, Int64 max_block_, UInt32 level_, Int64 mutation_)
39:         : partition_id(std::move(partition_id_)), min_block(min_block_), max_block(max_block_), level(level_), mutation(mutation_)
40:     {
41:     }
42: 
43:     bool operator<(const MergeTreePartInfo & rhs) const
44:     {
