167: SelectPartsDecision MergeTreeDataMergerMutator::selectPartsToMerge(
168:     FutureMergedMutatedPartPtr future_part,
169:     bool aggressive,
170:     size_t max_total_size_to_merge,
171:     const AllowedMergingPredicate & can_merge_callback,
172:     bool merge_with_ttl_allowed,
173:     const MergeTreeTransactionPtr & txn,
174:     PreformattedMessage & out_disable_reason,
175:     const PartitionIdsHint * partitions_hint)
176: {
177:     MergeTreeData::DataPartsVector data_parts = getDataPartsToSelectMergeFrom(txn, partitions_hint);
178: 
179:     auto metadata_snapshot = data.getInMemoryMetadataPtr();
180: 
181:     if (data_parts.empty())
182:     {
183:         out_disable_reason = PreformattedMessage::create("There are no parts in the table");
184:         return SelectPartsDecision::CANNOT_SELECT;
185:     }
186: 
187:     MergeSelectingInfo info = getPossibleMergeRanges(data_parts, can_merge_callback, txn, out_disable_reason);
188: 
189:     if (info.parts_selected_precondition == 0)
190:     {
191:         out_disable_reason = PreformattedMessage::create("No parts satisfy preconditions for merge");
192:         return SelectPartsDecision::CANNOT_SELECT;
193:     }
194: 
195:     auto res = selectPartsToMergeFromRanges(future_part, aggressive, max_total_size_to_merge, merge_with_ttl_allowed,
196:                                             metadata_snapshot, info.parts_ranges, info.current_time, out_disable_reason);
197: 
198:     if (res == SelectPartsDecision::SELECTED)
199:         return res;
200: 
201:     String best_partition_id_to_optimize = getBestPartitionToOptimizeEntire(info.partitions_info);
202:     if (!best_partition_id_to_optimize.empty())
203:     {
204:         return selectAllPartsToMergeWithinPartition(
205:             future_part,
206:             can_merge_callback,
207:             best_partition_id_to_optimize,
208:             /*final=*/true,
209:             metadata_snapshot,
210:             txn,
211:             out_disable_reason,
212:             /*optimize_skip_merged_partitions=*/true);
213:     }
214: 
