221: MergeTreeDataMergerMutator::PartitionIdsHint MergeTreeDataMergerMutator::getPartitionsThatMayBeMerged(
222:     size_t max_total_size_to_merge,
223:     const AllowedMergingPredicate & can_merge_callback,
224:     bool merge_with_ttl_allowed,
225:     const MergeTreeTransactionPtr & txn) const
226: {
227:     PartitionIdsHint res;
228:     MergeTreeData::DataPartsVector data_parts = getDataPartsToSelectMergeFrom(txn);
229: 
230:     if (data_parts.empty())
231:         return res;
232: 
233:     auto metadata_snapshot = data.getInMemoryMetadataPtr();
234: 
235:     PreformattedMessage out_reason;
236:     MergeSelectingInfo info = getPossibleMergeRanges(data_parts, can_merge_callback, txn, out_reason);
237: 
238:     if (info.parts_selected_precondition == 0)
239:         return res;
240: 
241:     Strings all_partition_ids;
242:     std::vector<IMergeSelector::PartsRanges> ranges_per_partition;
243: 
244:     String curr_partition;
245:     for (auto & range : info.parts_ranges)
246:     {
247:         if (range.empty())
248:             continue;
249:         const String & partition_id = range.front().getDataPartPtr()->info.partition_id;
250:         if (partition_id != curr_partition)
251:         {
252:             curr_partition = partition_id;
253:             all_partition_ids.push_back(curr_partition);
254:             ranges_per_partition.emplace_back();
255:         }
256:         ranges_per_partition.back().emplace_back(std::move(range));
257:     }
258: 
259:     for (size_t i = 0; i < all_partition_ids.size(); ++i)
260:     {
261:         auto future_part = std::make_shared<FutureMergedMutatedPart>();
262:         PreformattedMessage out_disable_reason;
263:         /// This method should have been const, but something went wrong... it's const with dry_run = true
264:         auto status = const_cast<MergeTreeDataMergerMutator *>(this)->selectPartsToMergeFromRanges(
265:                 future_part, /*aggressive*/ false, max_total_size_to_merge, merge_with_ttl_allowed,
266:                 metadata_snapshot, ranges_per_partition[i], info.current_time, out_disable_reason,
267:                 /* dry_run */ true);
268:         if (status == SelectPartsDecision::SELECTED)
269:             res.insert(all_partition_ids[i]);
270:         else
271:             LOG_TEST(log, "Nothing to merge in partition {} with max_total_size_to_merge = {} (looked up {} ranges): {}",
272:                 all_partition_ids[i], ReadableSize(max_total_size_to_merge), ranges_per_partition[i].size(), out_disable_reason.text);
273:     }
274: 
275:     String best_partition_id_to_optimize = getBestPartitionToOptimizeEntire(info.partitions_info);
276:     if (!best_partition_id_to_optimize.empty())
277:         res.emplace(std::move(best_partition_id_to_optimize));
278: 
279:     LOG_TRACE(log, "Checked {} partitions, found {} partitions with parts that may be merged: [{}] "
280:               "(max_total_size_to_merge={}, merge_with_ttl_allowed={})",
281:               all_partition_ids.size(), res.size(), fmt::join(res, ", "), max_total_size_to_merge, merge_with_ttl_allowed);
282:     return res;
283: }
